const I55AE215B1AV10000S = {"id":"I55AE215B1AV10000S","categorySlug":"servo-motor-drivers-lenze>inverter-drive","translations":{"ar":{"keys":[{"key":"حالة المنتج","value":"وصف محول تردد لينز i550-C، بقدرة 1.5 كيلوواط، أحادي الطور 230/240 فولت، STO محول التردد i550 هو جهاز تحكم مدمج ذو وظائف قابلة للتطوير. يتميز بتعدد استخداماته وموثوقيته وسهولة استخدامه. وهو يفي بمتطلبات توجيه التصميم البيئي، ومعيار EN IEC 61800-9-2. تشمل تطبيقاته: محركات السيور الناقلة، ومحركات الحركة، ومحركات اللف، ومحركات الرفع، وآلات البثق، وآلات التعبئة والتغليف، والمضخات، والمراوح، وغيرها\n(وزن 1.6 كجم)"},{"key":"حالة المنتج","value":"جديد بالكرتون"}]},"en":{"keys":[{"key":"product description","value":"Description Lenze frequency inverter i550-C, 1.5 kW, 1-phase 230/240V, STO The i550 cabinet frequency converter is a compact control cabinet device with scalable functionality. It is versatile, reliable, and easy to use. It meets the requirements of the Ecodesign Directive, standard EN IEC 61800-9-2. Applications include: conveyor drives, travel drives, winding drives, lifting drives, extruders, packaging machines, pumps, fans, \n(Weight   1.6 kg)"},{"key":"Product Condition","value":"New in Box "}]},"tr":{"keys":[{"key":"ürün açıklaması","value":"Lenze i550-C frekans invertörü, 1,5 kW, 1 fazlı 230/240V, STO i550 kabin frekans dönüştürücü, ölçeklenebilir işlevselliğe sahip kompakt bir kontrol kabini cihazıdır. Çok yönlü, güvenilir ve kullanımı kolaydır. Eko tasarım Direktifi ve EN IEC 61800-9-2 standardının gerekliliklerini karşılar. Uygulama alanları şunlardır: konveyör tahrikleri, hareket tahrikleri, sarma tahrikleri, kaldırma tahrikleri, ekstrüderler, paketleme makineleri, pompalar, fanlar vb.\n(Ağırlık 1.6 kg)"},{"key":"Ürün durumu","value":"Sıfır Kutusunda "}]}},"i18n":{"ar":{},"en":{},"tr":{}},"unCategorySlug":"","price":"contact"};
